import{_ as s,o as t,c as a,a6 as o,kE as p,kF as e,kG as i,kH as n,kI as g,kJ as _,kK as l,gU as c,jS as m,jT as d,jU as h}from"./chunks/framework.UYVGz2W_.js";const b=JSON.parse('{"title":"タスクの管理","description":"","frontmatter":{},"headers":[],"relativePath":"ja/supervisor-tasks/index.md","filePath":"ja/supervisor-tasks/index.md"}'),k={name:"ja/supervisor-tasks/index.md"};function u(f,r,P,S,v,x){return t(),a("div",null,[...r[0]||(r[0]=[o('<h1 id="タスクの管理" tabindex="-1">タスクの管理 <a class="header-anchor" href="#タスクの管理" aria-label="Permalink to “タスクの管理”">​</a></h1><h2 id="自分のタスクを確認する" tabindex="-1">自分のタスクを確認する <a class="header-anchor" href="#自分のタスクを確認する" aria-label="Permalink to “自分のタスクを確認する”">​</a></h2><p>通常、スーパーバイザーには、担当部署の管理に加えて、割り当てられたタスクがあります。つまり、自分の仕事をこなすこととチームの管理に時間を割く必要があるということです。 ここでは、自分が担当するタスクを効果的に管理する方法を説明します。</p><p>Kitsuにログインすると、画面の上部に「<strong>マイタスク</strong>」ボタンがあることに気づくでしょう。 ここから、<strong>ToDoリスト</strong>に直接アクセスできます。 デフォルトでは、リストは優先度順にソートされているため、リストの上部に表示されているタスクが、最初に処理すべきタスクです。</p><p>マイタスクページでは、生産、タスクタイプ、ステータス、その他の条件でタスクリストをフィルタリングできます。</p><p><img src="'+p+'" alt="Supervisor Todo ページ"></p><p>タスクの詳細を表示するには、<strong>ステータス</strong>をクリックしてコメントパネルを開きます。ここで、タスクにコメントを追加したり、必要に応じて新しいリビジョンを公開することができます。</p><p><img src="'+e+'" alt="Supervisor Todo 詳細ページ"></p><p>また、各ステータス列にドラッグ＆ドロップすることで、複数のタスクのステータスをすばやく更新することもできます。</p><p><img src="'+i+'" alt="Supervisor Todo Detailed Page board"></p><h2 id="プレビューの確認" tabindex="-1">プレビューの確認 <a class="header-anchor" href="#プレビューの確認" aria-label="Permalink to “プレビューの確認”">​</a></h2><p>チームの全員が各自のタスクを把握したので、今度は各自の作業を確認する必要があります。通常、アーティストがタスクを完了すると、レビューのためにあなたに連絡してきます。頻繁な中断は非生産的であり、集中力を維持することが難しくなります。これを避けるために、レビューのための特定の時間枠を設定します。このアプローチは、構造化されたスケジュールを提供することで、あなたとチームの両方に利益をもたらします。アーティストはフィードバックがいつ得られるかを知ることができ、それに応じて作業を計画することができます。一方、あなたは中断のない時間を自分のタスクに専念することができます。</p><p>画面上部の「<strong>マイチェック</strong>」ボタンをクリックすると、部署内のすべての<strong>WFA</strong>タスクのリストが表示されます。</p><p><img src="'+n+'" alt="Supervisor My Check Page"></p><p>このリストには、関連するすべての<strong>制作</strong>、<strong>タスクタイプ</strong>、および<strong>タスクステータス</strong>が含まれています。キット内の他のページと同様に、<strong>ステータス</strong>をクリックすると、右側に<strong>コメントパネル</strong>が開き、タスクを1つずつ確認することができます。</p><p>または、「リストからプレイリストを作成」ボタンを使用して、リスト上のすべてのタスクを含むプレイリストを作成することもできます。このプレイリストには、他のビューと同じオプションが用意されており、コメントパネルを開いたり、バージョンやタスクタイプを比較したり、注釈を追加したりすることができます。</p><p><img src="'+g+'" alt="Supervisor My Check Playlist"><img src="'+_+'" alt="Supervisor My Check Playlist Option"></p><p>別のオプションとして、<strong>タスクタイプページ</strong>に移動して、<strong>コンタクトシートとして表示</strong>を変更することもできます。たとえば、<strong>期限ステータス</strong>でフィルタリングして、<strong>今週期限</strong>を選択することができます。</p><p><img src="'+l+'" alt="スーパーバイザーのコンタクトシート"></p><p>ここから、コンタクトシートをクリックしてコメントパネルを開いたり、複数のタスクを選択してプレイリストを作成することができます。</p><h2 id="レビューの概念" tabindex="-1">レビューの概念 <a class="header-anchor" href="#レビューの概念" aria-label="Permalink to “レビューの概念”">​</a></h2><p>アーティストがコンセプトをアップロードすると、画面上部のナビゲーションメニューで「<strong>コンセプト」</strong>ページを選択して、そのコンセプトを確認することができます。</p><p><img src="'+c+'" alt="メニューコンセプト"></p><p>このページでは、アップロードされたすべてのコンセプトとそのステータス、割り当て、リンクされたアセットを確認できます。</p><p><img src="'+m+'" alt="コンセプトが入力されたステータス"></p><p>コンセプトを確認するには、ステータスをクリックしてコメントパネルを開きます。コメントパネルを拡大したり、フルスクリーン表示にすることができます。コメントを入力し、ステータスを「承認済み」または「却下」に設定し、「投稿」ボタンで変更を確定します。</p><p><img src="'+d+'" alt="コンセプトステータスのコメント"></p><p><strong>ステータス</strong>フィルタを使用してページを絞り込み、<strong>ニュートラル</strong>ステータスのすべてのコンセプトを表示することができます。</p><p><img src="'+h+'" alt="コンセプトステータスフィルタ"></p><p>さらに、アーティスト別にフィルタリングしたり、ソート順を変更したりして、レビューに必要なデータをより正確に絞り込むことができます。</p>',30)])])}const j=s(k,[["render",u]]);export{b as __pageData,j as default};
